r: rgb(60, 60, 60); font-family: Tahoma; line-height: 18px; &quot;&gt;знание японской и итальянской кухни&lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;\r\n\t&lt;span class=&quot;Apple-style-span&quot; style=&quot;border-collapse: collapse; color: rgb(60, 60, 60); font-family: Tahoma; line-height: 18px; &quot;&gt;&lt;strong&gt;&lt;strong&gt;Обязанности:&lt;/strong&gt;&lt;/strong&gt;&lt;br /&gt;\r\n\t&lt;/span&gt;&lt;/p&gt;\r\n&lt;ul style=&quot;margin-top: 10px; margin-right: 10px; margin-bottom: 10px; margin-left: 10px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 30px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; &quot;&gt;\r\n\t&lt;li style=&quot;margin-top: 0px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 0px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; list-style-type: disc; &quot;&gt;\r\n\t\t&lt;span class=&quot;Apple-style-span&quot; style=&quot;border-collapse: collapse; color: rgb(60, 60, 60); font-family: Tahoma; line-height: 18px; &quot;&gt;приготовление блюд японской и итальянской кухни&lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;\r\n\t&lt;span class=&quot;Apple-style-span&quot; style=&quot;border-collapse: collapse; color: rgb(60, 60, 60); font-family: Tahoma; line-height: 18px; &quot;&gt;&lt;strong&gt;&lt;strong&gt;Условия:&lt;/strong&gt;&lt;/strong&gt;&lt;br /&gt;\r\n\t&lt;/span&gt;&lt;/p&gt;\r\n&lt;ul style=&quot;margin-top: 10px; margin-right: 10px; margin-bottom: 10px; margin-left: 10px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 30px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; &quot;&gt;\r\n\t&lt;li style=&quot;margin-top: 0px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 0px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; list-style-type: disc; &quot;&gt;\r\n\t\t&lt;span class=&quot;Apple-style-span&quot; style=&quot;border-collapse: collapse; color: rgb(60, 60, 60); font-family: Tahoma; line-height: 18px; &quot;&gt;оплата и график работы по договоренности&lt;/span&gt;&lt;/li&gt;\r\n\t&lt;li style=&quot;margin-top: 0px; margin-right: 0px; margin-bottom: 0px; margin-left: 0px; padding-top: 0px; padding-right: 0px; padding-bottom: 0px; padding-left: 0px; border-top-width: 0px; border-right-width: 0px; border-bottom-width: 0px; border-left-width: 0px; border-style: initial; border-color: initial; border-collapse: collapse; -webkit-border-horizontal-spacing: 0px; -webkit-border-vertical-spacing: 0px; list-style-type: disc; &quot;&gt;\r\n\t\tбесплатное питание&lt;/li&gt;\r\n&lt;/ul&gt;\r\n');
INSERT INTO `oc_information_description` (`information_id`, `language_id`, `title`, `description`) VALUES ('3', '1', 'Заказ и Доставка', '&lt;p&gt;\r\n\t&lt;strong&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Для того, чтобы оформить заказ вы можете:&lt;/span&gt;&lt;/strong&gt;&lt;br /&gt;\r\n\t&lt;br /&gt;\r\n\t1. Позвонить по телефону &lt;span style=&quot;font-size: 14px;&quot;&gt;&lt;strong&gt;&lt;strong&gt;НОМЕР ТЕЛЕФОНА&lt;/strong&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;/span&gt;если вы заказываете в Колпино&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;\r\n\t&lt;span style=&quot;font-size: 14px;&quot;&gt;&lt;strong&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; &lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;&lt;strong&gt;&lt;strong&gt;НОМЕР ТЕЛЕФОНА&lt;/strong&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;/span&gt;если вы заказываете в Санкт-Петербург&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;\r\n\t&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;\r\n\t2. Воспользоваться нашим интернет магазином. Для этого в меню рядом с понравившимися вам блюдами нажимаете &amp;laquo;В корзину&amp;raquo;, а по окончании выбора &amp;laquo;Оформить заказ&amp;raquo;. При заполнении формы не забудьте оставить номер контактного телефона, по которому наш оператор свяжется с вами для подтверждения заказа.&lt;br /&gt;\r\n\t&lt;br /&gt;\r\n\t&lt;span style=&quot;font-size: 14px;&quot;&gt;&lt;strong&gt;Как получить заказ?&lt;/strong&gt;&lt;/span&gt;&lt;br /&gt;\r\n\t&lt;br /&gt;\r\n\tНаша служба доставки оперативно привезет его вам, по указанному вами адресу в удобное для вас время.&lt;br /&gt;\r\n\t&lt;br /&gt;\r\n\tПо любым интересующим вас вопросам вы можете проконсультироваться с нашими операторами по телефону&lt;strong&gt; НОМЕР ТЕЛЕФОНА&lt;/strong&gt;&lt;br /&gt;\r\n\t&lt;br /&gt;\r\n\tКаждое блюдо упаковывается с соответствующими соусами и столовыми приборами (маринованный имбирь, васаби, соевый соус, палочки).&lt;br /&gt;\r\n\t&lt;br /&gt;\r\n\tБесплатная доставка по Колпино при заказе на сумму от 400 рублей!&lt;/p&gt;\r\n&lt;p&gt;\r\n\tБесплатная доставка по Санкт-Петербургу при заказе на сумму от 500 рублей!&lt;/p&gt;\r\n&lt;p&gt;\r\n\tПри заказе на меньшую сумму стоимость доставки составит 100 рублей.&lt;/p&gt;\r\n');
