INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('59', '42', '0', 'Александр', 'Пользуюсь с удовольствием', '5', '1', '2011-02-25 07:36:19', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('60', '47', '0', 'Михаил', 'Товар очень понравился, быстро доставили', '5', '1', '2011-03-11 13:32:43', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('61', '42', '0', 'Наталья', 'вчера заказывала эти роллы - очень вкусные! и доставили их всего минут за 30-40. Буду заказывать еще =)', '5', '1', '2011-04-10 09:05:02', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('91', '87', '0', 'Георгий', 'Заказывал уже два раза! Из всех, что привозили по телефону, эти однозначно занимают первое место. Да и по сравнению с тем, что подают в большинстве ресторанов, евросуши сильно выигрывают! очень вкусно, очень качественно - молодцы!', '5', '1', '2011-12-31 01:43:14', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('63', '106', '0', 'Андрей', 'Весьма необычно, но очень вкусно! Ни где такого не пробовал.', '5', '1', '2011-02-26 05:17:39', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('64', '90', '0', 'Ксения', 'В наборе много  ролов и сушиков, их хватит что бы полакомиться большой компании или просто любителям вкусненького!!! Очень вкусно =))))', '5', '1', '2011-04-10 09:05:29', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('65', '89', '0', 'Анна', 'Это мои самые любимые!!!Спасибо большое - Очень сытно, вкусно и просто божественное сочетание индегриенов!!!!', '5', '1', '2011-04-10 09:05:49', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('66', '56', '0', 'Регина', 'Спасибо вам!!!!была приятна удивленна, очень понравились запеченные роллы с крабом, вкус изумительный и краб действительно настоящий!!!! ', '5', '1', '2011-04-04 11:09:07', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('67', '68', '0', 'Ксения', 'Вкуснятина, пальчики оближешь!!!!!', '5', '1', '2011-04-04 11:08:10', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('68', '35', '0', 'Антон', 'Такой вкусной филадельфии я еще не пробовал!!!!Рекомендую =)', '5', '1', '2011-04-04 11:07:54', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('83', '89', '0', 'Виолетта', 'Это наши одни из самых любимых с мужем!М-м-м!', '5', '1', '2011-09-23 06:02:04', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('87', '42', '55', 'Екатерина', 'Сегодня заказывала первый раз. Приятно удивлена!\r\nОбещали привезти через 1,5 часа. А привезли через 40 мин. Очень вкусно. Спасибо!', '5', '1', '2011-11-11 13:35:12', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('70', '42', '0', 'Алла', 'очень вкусно,быстро доставили,цена супер))))\r\nспасибо за Вашу работу))))', '5', '1', '2011-05-12 05:24:48', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('71', '87', '0', 'Еленка', 'Было незабываемо вкусно, хочу еще!)))\r\nЛучшие суши! Я теперь у вас постоянный клиент!', '5', '1', '2011-05-12 05:25:31', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('72', '87', '0', 'Еленка', 'Суши просто объедение....честно съела бы еще парочку таких же!)))\r\nЯ теперь ваш постоянный клиент!))))', '5', '1', '2011-05-12 05:25:10', '0000-00-00 00:00:00');
INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('73', '42', '0', 'Пэн', 'Очень понравилось , доставка в течении 30-40 минут. Спасибо !', '5', '1', '2011-06-05 11:43:36', '0000-00-00 00:00:00');
