INSERT INTO `oc_review` (`review_id`, `product_id`, `customer_id`, `author`, `text`, `rating`, `status`, `date_added`, `date_modified`) VALUES ('101', '83', '0', 'Елена', 'Сидела на сайте, выбирала, выбирала, всё определилась, а заказать не получилось, потому что глюк с сайтом: &quot;запрашиваемая страница не найдена&quot; и контактов на сайте нет...капец. Ваши айтишники просто МАЛАДЦЫ!', '1', '0', '2012-12-29 12:09:02', '0000-00-00 00:00:00');
